IF NOT (EXISTS (SELECT 1 FROM eval.shipments s JOIN eval.exceptions e ON e.CorrelationId=s.BusinessKey WHERE s.BusinessKey='SHP-5001' AND s.Status='Delivered' AND e.BusinessKey='EVAL-SHIPPING-001') AND NOT EXISTS (SELECT 1 FROM eval.transport_work_orders WHERE BusinessKey='EMPTY-SHP-5001')) THROW 51001, 'Scenario entity or linked defect not reproducible', 1; SELECT 'ENTITY_FOUND' EntityStatus,'eval.shipments' EntityTable,'BusinessKey' EntityColumn,'SHP-5001' ExpectedEntity,COUNT(*) ExactRowCount FROM eval.shipments WHERE BusinessKey='SHP-5001';
GO
